/**
 * Zipminator Video Production Engine
 * Powered by Veo 3.1 (Cinematic Video Generation)
 * 
 * Consumes the production manifest generated by generate-zipminator-video.js
 */

import { GoogleGenerativeAI } from '@google/generative-ai';
import fs from 'fs/promises';
import path from 'path';
import { fileURLToPath } from 'url';
import sharp from 'sharp';
import { exec } from 'child_process';
import util from 'util';

const execPromise = util.promisify(exec);

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const MANIFEST_PATH = path.join(__dirname, '../../video-output/zipminator-production-manifest.json');

async function generateVideos() {
  console.log('🎨 Starting Imagen 4.0 ultra Storyboard Engine...\n');

  // 1. Load Manifest
  let manifest;
  try {
    const data = await fs.readFile(MANIFEST_PATH, 'utf-8');
    manifest = JSON.parse(data);
    console.log(`📋 Loaded Manifest: ${manifest.project}`);
    console.log(`🖼️ Visual Model: ${manifest.config.veoModel}`);
  } catch (error) {
    console.error('❌ Error loading manifest. Run generate-zipminator-video.js first!');
    process.exit(1);
  }

  const genAI = new GoogleGenerativeAI(manifest.config.apiKey);
  const model = genAI.getGenerativeModel({ model: manifest.config.veoModel });

  const results = [];

  // 2. Generate Scenes
  for (const scene of manifest.production.scenes) {
    console.log(`\n🖼️ Generating Scene ${scene.id}...`);
    console.log(`   Prompt: ${scene.prompt.substring(0, 100)}...`);

    try {
      console.log(`   ⏳ Sending request to ${manifest.config.veoModel}...`);

      const result = await model.generateContent({
        contents: [{
          role: 'user',
          parts: [{ text: scene.prompt }]
        }]
      });

      const response = await result.response;

      // Handle Image Response
      let imageSaved = false;
      let outputUri = '';

      if (response.candidates && response.candidates[0].content.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            const buffer = Buffer.from(part.inlineData.data, 'base64');
            let filename = `scene_${scene.id}.png`;
            const outputPath = path.join(path.dirname(MANIFEST_PATH), filename);

            // Save raw image first
            await fs.writeFile(outputPath, buffer);
            console.log(`   ✅ Saved Raw: ${filename}`);

            // Apply Logo Overlay for Scene 9
            if (scene.id === 9) {
              console.log('   🎨 Overlaying Logos on Scene 9...');
              try {
                const zipLogoPath = path.join(__dirname, '../public/logos/zipminator.svg');
                const qdLogoPath = path.join(__dirname, '../public/logos/QDwordmark2.svg');

                // Check if logos exist
                await fs.access(zipLogoPath);
                await fs.access(qdLogoPath);

                const compositeBuffer = await sharp(buffer)
                  .composite([
                    { input: zipLogoPath, gravity: 'center', blend: 'over' },
                    { input: qdLogoPath, gravity: 'south', top: 800, blend: 'over' } // Adjust position as needed
                  ])
                  .toBuffer();

                await fs.writeFile(outputPath, compositeBuffer);
                console.log(`   ✨ Logos Applied to Scene 9`);
              } catch (err) {
                console.warn(`   ⚠️ Failed to overlay logos: ${err.message}`);
              }
            }

            outputUri = outputPath;
            imageSaved = true;
            break;
          }
        }
      }

      if (!imageSaved) {
        const text = response.text();
        if (text) {
          console.log(`   ℹ️ Model returned text: ${text.substring(0, 100)}...`);
          outputUri = text;
        } else {
          throw new Error('No image data found in response');
        }
      }

      results.push({
        sceneId: scene.id,
        status: 'success',
        uri: outputUri,
        prompt: scene.prompt
      });

    } catch (error) {
      console.error(`   ❌ Error generating scene ${scene.id}:`, error.message);
      results.push({
        sceneId: scene.id,
        status: 'error',
        error: error.message
      });

      if (error.message.includes('429')) {
        console.log('   ⚠️ Rate limit. Pausing for 60s...');
        await new Promise(r => setTimeout(r, 60000));
      }
    }

    // Polite pause
    await new Promise(r => setTimeout(r, 2000));
  }

  // 3. Update Manifest with Results
  manifest.production.results = results;
  await fs.writeFile(MANIFEST_PATH, JSON.stringify(manifest, null, 2));

  console.log(`\n✅ Storyboard Generation Complete. Manifest updated.`);
  console.log(`📊 Success Rate: ${results.filter(r => r.status === 'success').length}/${results.length}`);

  // 4. Generate Audio and Assemble Clips
  console.log('\n🎙️ Generating Audio and Assembling Clips...');
  const clipPaths = [];
  const videoDir = path.dirname(MANIFEST_PATH);

  for (const scene of manifest.production.scenes) {
    try {
      console.log(`   🎬 Processing Scene ${scene.id}...`);

      const imagePath = path.join(videoDir, `scene_${scene.id}.png`);
      const audioPath = path.join(videoDir, `scene_${scene.id}.aiff`);
      const clipPath = path.join(videoDir, `clip_${scene.id}.mp4`);

      // Check if image exists
      try {
        await fs.access(imagePath);
      } catch {
        console.warn(`   ⚠️ Image for scene ${scene.id} missing. Skipping.`);
        continue;
      }

      // A. Generate Voiceover
      // Escape quotes in voiceover text
      const safeVoiceover = scene.voiceover.replace(/"/g, '\\"');
      const ttsCmd = `say -v Ava -o "${audioPath}" "${safeVoiceover}"`;
      await execPromise(ttsCmd);
      console.log(`      🔊 Audio generated`);

      // B. Create Video Clip (Image + Audio)
      // -loop 1: Loop image
      // -shortest: End when audio ends
      // -pix_fmt yuv420p: Ensure compatibility
      // -t 10: Fallback duration if audio fails (though shortest handles it)
      // We add a slight fade in/out for elegance
      // Calculate fade out start time
      const fadeOutStart = scene.duration - 0.5;
      const ffmpegCmd = `ffmpeg -y -loop 1 -i "${imagePath}" -i "${audioPath}" -c:v libx264 -tune stillimage -c:a aac -b:a 192k -pix_fmt yuv420p -shortest -vf "fade=t=in:st=0:d=0.5,fade=t=out:st=${fadeOutStart}:d=0.5" "${clipPath}"`;

      await execPromise(ffmpegCmd);
      console.log(`      🎞️ Clip created: clip_${scene.id}.mp4`);
      clipPaths.push(clipPath);

    } catch (err) {
      console.error(`   ❌ Failed to process scene ${scene.id}: ${err.message}`);
    }
  }

  // 5. Concatenate Clips
  if (clipPaths.length > 0) {
    console.log('\n🎬 Stitching Final Video...');
    const listPath = path.join(videoDir, 'concat_list.txt');
    const fileContent = clipPaths.map(p => `file '${p}'`).join('\n');
    await fs.writeFile(listPath, fileContent);

    const finalVideoPath = path.join(videoDir, 'zipminator_promo.mp4');
    const concatCmd = `ffmpeg -y -f concat -safe 0 -i "${listPath}" -c copy "${finalVideoPath}"`;

    try {
      await execPromise(concatCmd);
      console.log(`\n✨✨✨ VIDEO GENERATION COMPLETE ✨✨✨`);
      console.log(`👉 Output: ${finalVideoPath}`);
    } catch (err) {
      console.error(`   ❌ Final Assembly Failed: ${err.message}`);
    }
  } else {
    console.warn('   ⚠️ No clips generated. Cannot assemble video.');
  }
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  generateVideos().catch(console.error);
}

export { generateVideos };
